steps.solution:
report = {
    "month": "april",
    "orders": [
        {"id": "A1", "items": [{"sku": "x", "price": 10}, {"sku": "y", "price": 5}]},
        {"id": "A2", "items": [{"sku": "x", "price": 10}]},
        {"id": "A3", "items": [{"sku": "z", "price": 12}, {"sku": "x", "price": 10}]},
    ],
}

total = 0
for order in report["orders"]:
    for item in order["items"]:
        total += item["price"]

print(total)
